import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();
async function createUserWithPost(): Promise<void> {
  // Create a user and a post in one transaction (nested write)
  const user = await prisma.user.create({
    data: {
      email: 'alice@example.com',
      name: 'Alice',
      posts: { create: { title: 'My First Post' } },
    },
    include: { posts: true }, // Include related posts in result
  });
  console.log('Created user:', user.name, 'with', user.posts.length, 'post(s)');
  // Query with filtering
  const recentPosts = await prisma.post.findMany({
    where: { authorId: user.id },
    orderBy: { id: 'desc' },
    take: 10,
  });
  console.log('Recent posts:', recentPosts.length);
}
createUserWithPost();
